## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGchoicemacros.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
Context()->operators->remove("U");
Context()->noreduce('(-x)+y','(-x)-y');
$var = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'Z');
Context()->variables->are($var => 'Real');

@ones = (1) x 90;
@ints = (2..91);
@fracs = ();
for my $j (2..10) {
  for my $i (1..10) {
    push(@fracs, Fraction($i,$j));
  }
}

@signs = (1,list_random(-1,1));
@signs = (@signs)[NchooseK(2,2)];
@coefs = (list_random(@fracs), list_random(@ones, @ints, @fracs));
@coefs = (@coefs)[NchooseK(2,2)];
@coefs = map {$signs[$_-1]*$coefs[$_-1]} (1,2);
@terms = ();
for my $i (1,2) {
  push(@terms, Formula("$coefs[$i-1]*$var"));
}
$sum = Formula(join('+', @terms))->reduce;

$c = $coefs[0] + $coefs[1];

Context("Form");
Context()->operators->remove("U");
Context()->variables->are($var => 'Real');
$ans = Formula("($c)$var");

############################################################
# Body
############################################################

BEGIN_PGML
Simplify the expression by combining like terms if possible.

[`[$sum]`]

[_]{$ans}{20}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
